window.__QUIZ_DATA__=[{"id":"theory>Physics>2014>1","subject":"Physics","year":"2014","type":"Theory","sub_label":"1","group":"FINAL","topic":"PROJECTILE MOTION :","question":"A particle is projected horizontally at 10ms-1 from the top of a tower 20m high. Calculate the horizontal distance travelled by the particle when it hits the level ground. [g = 10ms-2]","images":[],"marking_scheme":"Parameters given; Initial velocity, U = 0ms-1,height,  S = 20m    Recall that :S = ut + 1/2gt2   20 = 0 x t + 1/2 x 10 x t2    20 = 0 + 5t2    t2 = 20/5    t = &radic;4&nbsp;    t = 2sec   t = 2sec, u = 20m/s","marks":"3","difficulty":"2"},{"id":"theory>Physics>2014>2","subject":"Physics","year":"2014","type":"Theory","sub_label":"2","group":"FINAL","topic":"PROJECTILE MOTION :","question":"A tennis ball projected at an angle \u03b8 attains a range R = 78m. If the velocity imparted to the ball by the racket is 30ms-1, calculate \u03b8. [g = 10ms-2]","images":[],"marking_scheme":"Recall that:R=U2sin\u03b8g   Parameters given; Range, R= 78m, acceleration due to gravity,g = 10ms-2, \u03b8 = ?, U = 30ms-1   \u2234 78=(30)2sin2\u03b810 sin2\u03b8 = 780/900   sin\u03b8 = 0.8666   2\u03b8 = sin-10.8666 =60o   = 30 o","marks":"3","difficulty":"2"},{"id":"theory>Physics>2014>3","subject":"Physics","year":"2014","type":"Theory","sub_label":"3","group":"","topic":"MAGNETIC FIELD : MAGNETIC FORCE ON A MOVING CHARGED PARTICLE","question":"An electron moves with a speed of 2.00 x 107ms-1 in an orbit in a uniform magnetic field of 1.2 x 10-3T. Calculate the radius of the orbit.   [Mass of an electron = 9.11 x 10-31kg, charge on an electron = 1.61 x 10-19C]","images":[],"marking_scheme":"Recall that:mV2/r = Bqv : That is, centripetal force = magnetic field force    r=mVBq    r=9.11 x 10-31 x 2.00 x 1071.20 x 10-3 x 1.61 x 10-19 = 9.43 x 10-2m","marks":"3","difficulty":"3"},{"id":"theory>Physics>2014>4","subject":"Physics","year":"2014","type":"Theory","sub_label":"4","group":"","topic":"HOOKE\u2019S LAW, YOUNG\u2019S MODULES AND WORK DONE IN SPRINGS AND STRING :","question":"A metallic bar 50cm long has a uniform cross-sectional area of 4.0cm2. If a tensile force of 35KN produces an extension of 0.25mm, calculate the value of young's modulus.","images":[],"marking_scheme":"Recall that:Y = F/A/e/l   F = 35KN, A = 4cm2 = 0.04m2, e = 0.25mm = 0.00025m    l = 50cm/100 = 0.5m   Area, A = 4.0cm2 = 4/_(1002m = 0.0004m   Tensile Force,  F = 35N   extension, e = 0.25mm = 0.25/1000m = 0.00025m   Young modulus = F/A/e/l = F x L/A x e    = 35 x 0.5/0.0004 x 0.00025 = 1.75 x 1011Nm -2","marks":"3","difficulty":"2"},{"id":"theory>Physics>2014>5>a","subject":"Physics","year":"2014","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"ELECTRIC FIELD : ELECTRIC CONDUCTION THROUGH MATERIALS","question":"Explain how a gas can be made to conduct electricity","images":[],"marking_scheme":"The molecules /atom of gas must be ionized before the gas can conduct electricity .ionisation of the gas requires that the gas pressure is very low within the closure and a very high voltage is applied to the enclosed gas","marks":"2","difficulty":"1"},{"id":"theory>Physics>2014>5>b","subject":"Physics","year":"2014","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"ELECTRIC FIELD : PRODUCTION OF ELECTRIC CHARGES","question":"Name the electric charge carriers in gases.","images":[],"marking_scheme":"The electric charge carries in gases are the   -electrons    -ions","marks":"1","difficulty":"1"},{"id":"theory>Physics>2014>6>a","subject":"Physics","year":"2014","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"STRUCTURE OF THE ATOM : PHOTOELECTRIC EFFECT","question":"The diagram above represents the graph of electron energy against the frequency of the radiation incident on a metal surface.   Interpret the slope of the graph","images":["data:image/png;base64,"],"marking_scheme":"The slope of the graph is the plank constant, (h)","marks":"1","difficulty":"3"},{"id":"theory>Physics>2014>6>b","subject":"Physics","year":"2014","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"STRUCTURE OF THE ATOM : PHOTOELECTRIC EFFECT","question":"The diagram above represents the graph of electron energy against the frequency of the radiation incident on a metal surface.   Interpret the intercept OC","images":["data:image/png;base64,"],"marking_scheme":"Intercept, OC represents  the work function(f) of the metal","marks":"1","difficulty":"3"},{"id":"theory>Physics>2014>6>c","subject":"Physics","year":"2014","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"STRUCTURE OF THE ATOM : PHOTOELECTRIC EFFECT","question":"The diagram above represents the graph of electron energy against the frequency of the radiation incident on a metal surface.   Interpret the intercept OK.","images":["data:image/png;base64,"],"marking_scheme":"Intercept Ok, depicts the threshold frequency, fo. of the incidents radiation","marks":"1","difficulty":"3"},{"id":"theory>Physics>2014>7>a","subject":"Physics","year":"2014","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"STRUCTURE OF THE ATOM : PHOTOELECTRIC EFFECT","question":"State two conditions under which photo-electrons can be emitted from the surface of a metal.","images":[],"marking_scheme":"-the wavelength of the incidents radiation must be less than the threshold wave length for metal surfaces   -the frequency of the incidents radiation must be greater than the threshold frequency   -the energy of the protons radiation must be greater than the work function","marks":"2","difficulty":"2"},{"id":"theory>Physics>2014>7>b","subject":"Physics","year":"2014","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"WAVE-PARTICLE PARADOX : DUALITY OF MATTER","question":"List two particle characteristics of electromagnetic waves","images":[],"marking_scheme":"Photoelectric affects  Thermionic emission   Radiations from the heated bodies   Emission and absorption of light [incandescence]  Compton effects","marks":"2","difficulty":"2"},{"id":"theory>Physics>2014>8>a>i","subject":"Physics","year":"2014","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"MOTION : SIMPLE IDEAS OF CIRCULAR MOTION","question":"Give two example of rotational motion","images":[],"marking_scheme":"-The rotation of the earth about its axis   - A cricket ball spinning about its axis    - The wheel of a moving car.    - The rotation of the blades of an electric fan.","marks":"1","difficulty":"1"},{"id":"theory>Physics>2014>8>a>ii","subject":"Physics","year":"2014","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"MOTION : TYPES OF MOTION","question":"Give two example of linear motion","images":[],"marking_scheme":"- A car travelling from Ibadan to Lagos   - A bee flying from one flower to another.  - A ball rolling on a straight track","marks":"1","difficulty":"1"},{"id":"theory>Physics>2014>8>b","subject":"Physics","year":"2014","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"FLUID AT REST : VOLUME, DENSITY AND RELATIVE DENSITY","question":"Describe a laboratory experiment to determine the density of an irregularly shaped solid.","images":[],"marking_scheme":"The mass m of the solid is determined using a chemical /beam balance ,a graduated measuring cylinder is partially filled with water and the initial volume V1 is recorded the solid is completely immersed in the water and the final volume v2 is recorded     Volume of the solid =V2 - V1   Density of the solid p=mass / volume  =m/v2-v1","marks":"3","difficulty":"3"},{"id":"theory>Physics>2014>8>c","subject":"Physics","year":"2014","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"NEWTON\u2019S LAWS OF MOTION : SECOND LAW","question":"State Newton's second law of motion","images":[],"marking_scheme":"The Newton second law of motion states that the rate of change of momentum is directly proportional to the impressed force and takes place in the direction of that force.","marks":"2","difficulty":"2"},{"id":"theory>Physics>2014>8>d","subject":"Physics","year":"2014","type":"Theory","sub_label":"d","group":"CLOSENESS","topic":"NEWTON\u2019S LAWS OF MOTION : FIRST LAW","question":"Explain the term inertia","images":[],"marking_scheme":"Inertia is the term given to the tendency of an object in  uniform motion to remain in this state of motion, or an object at rest to remain at rest.  -the more mass a body has ,the greater is its inertia","marks":"1","difficulty":"1"},{"id":"theory>Physics>2014>8>e>i","subject":"Physics","year":"2014","type":"Theory","sub_label":"i","group":"FINAL","topic":"NEWTON\u2019S LAWS OF MOTION : SECOND LAW","question":"The diagram above illustrates a body of mass 5.0kg being pulled by a horizontal force F. If the body accelerates at 2.0ms-1 and experiences a frictional force of 5N. Calculate the net force on it    [g = 10ms-2]","images":["data:image/png;base64,"],"marking_scheme":"Parameters given; Mass = 5kg, Acceleration,a = 20ms-2, Force,F1 = 5N, F = ?   (i) Net force = F - F1 = ma = 5 x 2 = 10N","marks":"2","difficulty":"3"},{"id":"theory>Physics>2014>8>e>ii","subject":"Physics","year":"2014","type":"Theory","sub_label":"ii","group":"FINAL","topic":"NEWTON\u2019S LAWS OF MOTION : SECOND LAW","question":"The diagram above illustrates a body of mass 5.0kg being pulled by a horizontal force F. If the body accelerates at 2.0ms-1 and experiences a frictional force of 5N. Calculate the magnitude of F   [g = 10ms-2]","images":["data:image/png;base64,"],"marking_scheme":"Magnitude  of F = F1 + net force (ma)    = 5 + 10 = 15N","marks":"1","difficulty":"3"},{"id":"theory>Physics>2014>8>e>iii","subject":"Physics","year":"2014","type":"Theory","sub_label":"iii","group":"FINAL","topic":"MOTION : SOLID FRICTION","question":"The diagram above illustrates a body of mass 5.0kg being pulled by a horizontal force F. If the body accelerates at 2.0ms-1 and experiences a frictional force of 5N. Calculate the coefficient of kinetic friction.   [g = 10ms-2]","images":["data:image/png;base64,"],"marking_scheme":"Coefficient of kinetic friction   from the formula   F1 \u2264 \u03bcR    \u2234 m = F1/R   where:   \u03bc = coefficient of kinetic friction    F1 = Frictional force    R = reaction = mg = 5 x 10 = 50N    \u2234 15/*:5x10     =0.3","marks":"1","difficulty":"3"},{"id":"theory>Physics>2014>9>a","subject":"Physics","year":"2014","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"HEAT ENERGY : HEAT CAPACITY","question":"Define heat capacity and state its unit.","images":[],"marking_scheme":"Heat capacity of a substance is the quantity of heat required to raise the temperature of unit mass of the substance by 1oC (or 1K). The unit is Joules per kilogram per Kelvin (J/kg.K)","marks":"2","difficulty":"1"},{"id":"theory>Physics>2014>9>b","subject":"Physics","year":"2014","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"HEAT ENERGY : EFFECTS OF HEAT ON MATTER","question":"List two effects of heat on a substance.","images":[],"marking_scheme":"- it leads to expansion of a substance /contraction  - It leads to change of state   - it changes in colour","marks":"2","difficulty":"1"},{"id":"theory>Physics>2014>9>c","subject":"Physics","year":"2014","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"HEAT ENERGY : THERMAL EXPANSION","question":"Explain how a tightly fitted glass stopper could be removed from a reagent bottle.","images":[],"marking_scheme":"The neck of the glass bottle should be warmed gradually from outside using warm cloth this makes the glass to expand creating space for the cock to be removed","marks":"2","difficulty":"2"},{"id":"theory>Physics>2014>9>d>i","subject":"Physics","year":"2014","type":"Theory","sub_label":"i","group":"FINAL","topic":"HEAT ENERGY : HEAT CAPACITY","question":"A quantity of pepper soup of mass 800g poured into a plastic container with a tight fitting lid has a temperature of 30oC. The container is then placed in a microwave oven rated 1200W and operated for 3 minutes.   calculate the final temperature attained by the soup. (Assuming no heat losses)   [Take specific heat capacity of the soup = 4000 Jkg-1K-1]","images":[],"marking_scheme":"Parameters given; mass = 800g = 0.8kg, \u03b81 = 30oc, \u03b82 = ?   \u03b8 = \u03b82 - \u03b81    Power = 1200W, C = 4000JKg-1K-1   time = 3 mins = (3 x 60) = 180sec   It should be noted that; Heat gained by the pepper soup = mc\u03b8   power = Heat/time = energy/time   \u2234 Heat = power x time    = 1200 x 180 = 216,000 = mc\u03b8   \u2234 \u03b8 = 216000/mc    \u03b8 = 216000/0.8 x 4000 = 67.5oc    Final temperature = 67.5 + 30 = 97.5oC","marks":"4","difficulty":"3"},{"id":"theory>Physics>2014>9>d>ii","subject":"Physics","year":"2014","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"HEAT ENERGY : HEAT TRANSFER","question":"A quantity of pepper soup of mass 800g poured into a plastic container with a tight fitting lid has a temperature of 30oC. The container is then placed in a microwave oven rated 1200W and operated for 3 minutes.   Explain why containers with tight-fitting lids are not suitable for use in microwave cooking.   [Take specific heat capacity of the soup = 4000 Jkg-1K-1]","images":[],"marking_scheme":"The molecules of the the steam from the content are confined within the container as the temperature increases the rate of collision of the molecules with walls of the container increases thus the pressure inside the container increases If it is tightly fitted ,the pressure can can make the container burst thus releasing its hot content","marks":"2","difficulty":"2"},{"id":"theory>Physics>2014>9>d>iii","subject":"Physics","year":"2014","type":"Theory","sub_label":"iii","group":"CLOSENESS","topic":"HEAT ENERGY : THERMAL EXPANSION","question":"A quantity of pepper soup of mass 800g poured into a plastic container with a tight fitting lid has a temperature of 30oC. The container is then placed in a microwave oven rated 1200W and operated for 3 minutes.   when the soup is brought out and allowed to cool, a dent is observed on the container. Explain    [Take specific heat capacity of the soup = 4000 Jkg-1K-1]","images":[],"marking_scheme":"The container will dent because the condensation of the steam in the container will lead to a decrease in pressure in the container making the atmospheric pressure greater than the pressure in the container","marks":"2","difficulty":"2"},{"id":"theory>Physics>2014>10>a","subject":"Physics","year":"2014","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"SOUND WAVES : CHARACTERISTICS OF SOUND","question":"State the three characteristic of sound and the factor on which each of they depend.","images":[],"marking_scheme":"- Pitch depends on the frequency of the sound wave    - Loudness depends on the mass/amplitude of the air which can be set into vibration    - Quality/timbre  depends on the overtones/harmonics  present in the note.","marks":"1","difficulty":"1"},{"id":"theory>Physics>2014>10>b","subject":"Physics","year":"2014","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"SOUND WAVES : RESONANCE","question":"Explain resonance as applied to sound","images":[],"marking_scheme":"Resonance is a phenomenon which occurs whenever a particular body or system is set in oscillation at its own natural frequency as a result of impulses or signal, received from some other system or body which is vibrating with the same frequency.   When the imposed frequency is the same as the natural frequency, the vibration build up to a large amplitude. Therefore, Resonance is an effect caused by a vibrating body setting another body vibrating both having the same natural frequency. Resonance is what happens when a book placed on a surface is blown by a rotating fan.","marks":"2","difficulty":"2"},{"id":"theory>Physics>2014>10>c","subject":"Physics","year":"2014","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"SOUND WAVES : ECHOES AND REVERBERATION","question":"What role does echo play in the construction of a concert hall?","images":[],"marking_scheme":"Echo sensitisies the construction engineers on the need to line the interior wall with appropriate sound absorbing materials","marks":"2","difficulty":"2"},{"id":"theory>Physics>2014>10>d>i","subject":"Physics","year":"2014","type":"Theory","sub_label":"i","group":"FINAL","topic":"SIMPLE HARMONIC MOTION : PERIOD, FREQUENCY AND AMPLITUDE OF A BODY EXECUTING S.H.M","question":"The surface of an ear drum (assumed circular) has a radius 2.1mm. It resonates with an amplitude of 0.8 x 10-7m as a result of impulses received from an external body vibrating at 2400Hz. If the resulting pressure change on the ear drum is 3.6 x 10-5Nm-2, calculate the period of oscillation    [\u03c0 = 3.142]","images":[],"marking_scheme":"Period of oscillation T = 1/F = 1/2400 = 0.00042","marks":"2","difficulty":"3"},{"id":"theory>Physics>2014>10>d>ii","subject":"Physics","year":"2014","type":"Theory","sub_label":"ii","group":"","topic":"SIMPLE HARMONIC MOTION : SPEED AND ACCELERATION OF S.H.M","question":"The surface of an ear drum (assumed circular) has a radius 2.1mm. It resonates with an amplitude of 0.8 x 10-7m as a result of impulses received from an external body vibrating at 2400Hz. If the resulting pressure change on the ear drum is 3.6 x 10-5Nm-2, calculate the velocity    [\u03c0 = 3.142]","images":[],"marking_scheme":"Velocity = V = f\u03bb = 2400x0.8x10-7  = 2.4 x 103 x 0.8 x 10-7  = 1.2 x 104-7  = 1.2 x 10-3m/s","marks":"2","difficulty":"3"},{"id":"theory>Physics>2014>10>d>iii","subject":"Physics","year":"2014","type":"Theory","sub_label":"iii","group":"FINAL","topic":"SIMPLE HARMONIC MOTION : SPEED AND ACCELERATION OF S.H.M","question":"The surface of an ear drum (assumed circular) has a radius 2.1mm. It resonates with an amplitude of 0.8 x 10-7m as a result of impulses received from an external body vibrating at 2400Hz. If the resulting pressure change on the ear drum is 3.6 x 10-5Nm-2, calculate the acceleration. [\u03c0 = 3.142]","images":[],"marking_scheme":"Acceleration   a =w 2 r =2 \u220ffr   =2x3.14x2400 2 x0.8x10 -7   = 18.2ms -2","marks":"2","difficulty":"3"},{"id":"theory>Physics>2014>10>d>iv","subject":"Physics","year":"2014","type":"Theory","sub_label":"iv","group":"","topic":"SIMPLE HARMONIC MOTION : SPEED AND ACCELERATION OF S.H.M","question":"The surface of an ear drum (assumed circular) has a radius 2.1mm. It resonates with an amplitude of 0.8 x 10-7m as a result of impulses received from an external body vibrating at 2400Hz. If the resulting pressure change on the ear drum is 3.6 x 10-5Nm-2, calculate the force. [\u03c0 = 3.142]","images":[],"marking_scheme":"To calculate force  Pressure = Force   Area   radius = 2.1mm = 0.0021m   Area of circular = \u03c0r2 = 3.14 x (0.0021)2  Area = 1.38 x 10-5m2  3.6 x 10-5 =   Force/1.38 x 10-5    Force = 3.6 x 10-5 x 1.38 x 10-5     = 4.968 x 10^(-5+(-5)   = 4.968 x 10-11N","marks":"2","difficulty":"3"},{"id":"theory>Physics>2014>11>a","subject":"Physics","year":"2014","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"ELECTRIC FIELD : ELECTRIC CURRENT, POTENTIAL DIFFERENCE, RESISTANCE, E.M.F. AND INTERNAL RESISTANCE","question":"Define electromotive force.","images":[],"marking_scheme":"Electromotive force of a cell is the energy needed to take a unit positive charge arround a circuit in which the cell is connected   - the p.d across the terminal of the cell when the cell/battery/generator is on open circuit   -the energy per unit charge transformed in the cell","marks":"2","difficulty":"1"},{"id":"theory>Physics>2014>11>b>i","subject":"Physics","year":"2014","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"ELECTRIC FIELD : POTENTIAL DIFFERENCE AND ELECTRIC CURRENT","question":"State the principle of operation of a potentiometer.","images":[],"marking_scheme":"- The p.d of across the wire is directly proportional to the length of the wire   -when a steady current flows through a uniform wire , equal  lengths of the wire will have equal potentials difference","marks":"2","difficulty":"2"},{"id":"theory>Physics>2014>11>b>ii","subject":"Physics","year":"2014","type":"Theory","sub_label":"ii","group":"","topic":"ELECTRIC FIELD : POTENTIAL DIFFERENCE AND ELECTRIC CURRENT","question":"State two advantages that a potentiometer has over a voltmeterin measuring potential difference.","images":[],"marking_scheme":"- It is very accurate/has no errors   - It is more sensitive    - It eliminates errors due to the internal internal resistance of the cell","marks":"1","difficulty":"2"},{"id":"theory>Physics>2014>11>c>i","subject":"Physics","year":"2014","type":"Theory","sub_label":"i","group":"","topic":"ELECTRIC FIELD : ELECTROSTATICS","question":"Sketch and a label a diagram of a gold-leaf electroscope","images":["data:image/png;base64,"],"marking_scheme":"","marks":"3","difficulty":"2"},{"id":"theory>Physics>2014>11>c>ii","subject":"Physics","year":"2014","type":"Theory","sub_label":"ii","group":"","topic":"ELECTRIC FIELD : ELECTROSTATICS","question":"Give one use of a gold-leaf electroscope.","images":[],"marking_scheme":"Detects  the [electrostatics] charge   Detects the nature of [electrostatic] charge   Determine the magnitude of the induced charges","marks":"1","difficulty":"1"},{"id":"theory>Physics>2014>11>d>i","subject":"Physics","year":"2014","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"MAGNETIC FIELD : USE OF ELECTROMAGNETS","question":"Explain the action of a magnetic relay.","images":[],"marking_scheme":"The mode of action of magnetic relay relies on the principle of electromagnetic induction ,a small current passing through one circuit controls another circuit containing devices which require larger current","marks":"2","difficulty":"2"},{"id":"theory>Physics>2014>11>d>ii","subject":"Physics","year":"2014","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"ELECTROMAGNETIC FIELD : FARADAY\u2019S LAW","question":"List two factors which determine the magnitude of an induced emf in a coil.","images":[],"marking_scheme":"- Speed of rotation of the coil   - Cross section area of the coil   - Number of turns in  the coil.","marks":"1","difficulty":"2"},{"id":"theory>Physics>2014>11>d>iii","subject":"Physics","year":"2014","type":"Theory","sub_label":"iii","group":"","topic":"MAGNETIC FIELD : MAGNETIC FORCE ON A MOVING CHARGED PARTICLE","question":"A current of 5A passes through a straight wire in a uniform magnetic field of flux density 2.0 x 10-3T. Calculate the force per unit length exerted on the wire when it is inclined at 30o to the field.","images":[],"marking_scheme":"Parameters given:B = 2.0 x 10-3T, I = 5A, \u03b8 = 30o, L = ? , F = ?   from the formula   F = BILsin\u03b8   To get force per unit length, divide through by L    F/L = BILsin\u03b8/L = BIsin\u03b8   Force per unit length = F/L    = 2.0 x 10-3 x 5sin30o    = 10.0 x 10-3 x 0.5    = 5.0 x 10-3Nm-1","marks":"1","difficulty":"3"},{"id":"theory>Physics>2014>12>a","subject":"Physics","year":"2014","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"STRUCTURE OF THE ATOM : PHOTOELECTRIC EFFECT","question":"Write Einstein's photoelectric equation and identify each component of the equation.","images":[],"marking_scheme":"Einsten photoelectric equation is given as: E=W\u2214KEmax  E=Energy of incidence radiation   W=Work function   K.Emax=maximum kinetic energy of photoelectron","marks":"2","difficulty":"2"},{"id":"theory>Physics>2014>12>b>i","subject":"Physics","year":"2014","type":"Theory","sub_label":"i","group":"","topic":"STRUCTURE OF THE ATOM : PHOTOELECTRIC EFFECT","question":"For a photocell, state one factor each that is responsible for the:   (i) emission   (ii) rate of emission   (iii) energy of photoelectrons","images":[],"marking_scheme":"Emission -frequency/wavelenght of incident radiation   Rate of emission -intensity of incident radiation /number of protons   Energy of photoelectrons- frequency/wavelength of incident radiation","marks":"3","difficulty":"2"},{"id":"theory>Physics>2014>12>b>ii","subject":"Physics","year":"2014","type":"Theory","sub_label":"ii","group":"","topic":"STRUCTURE OF THE ATOM : PHOTOELECTRIC EFFECT","question":"For a photocell, state one factor each that is responsible for the rate of emission","images":[],"marking_scheme":"Rate of emission -intensity of incident radiation /number of protons","marks":"1","difficulty":"2"},{"id":"theory>Physics>2014>12>b>iii","subject":"Physics","year":"2014","type":"Theory","sub_label":"iii","group":"","topic":"STRUCTURE OF THE ATOM : PHOTOELECTRIC EFFECT","question":"For a photocell, state one factor each that is responsible for the energy of photoelectrons","images":[],"marking_scheme":"Energy of photoelectrons- frequency/wavelength of incident radiation","marks":"1","difficulty":"2"},{"id":"theory>Physics>2014>12>c>i","subject":"Physics","year":"2014","type":"Theory","sub_label":"i","group":"","topic":"STRUCTURE OF THE NUCLEUS : FUSION AND FISSION","question":"Two nuclear equations are given below:    222PRn \u2192 21884Po + q2He .......................................................................................(equation A)    21483BI \u2192 21484Po + mnX ...............................................................................(equation B)    Determine the values of:   (\u03b1) p and q in equation A;   (\u03b2) m and n in equation B and identify X","images":[],"marking_scheme":"Given: the nuclear reaction,   222PRn \u2192 21884Po + q2He    P = 84 + 2 = 86    q = 222 - 218 = 4    21483Bi \u2192 21484Po + mnX    m = 214 - 214 = 0   m = 0   n = 83 - 84 = -1,   n = -1   0-1X   X is an electron","marks":"1","difficulty":"3"},{"id":"theory>Physics>2014>12>c>ii","subject":"Physics","year":"2014","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"STRUCTURE OF THE NUCLEUS : RADIOACTIVITY","question":"Give a reason why it is important to dispose of radioactive waste safely.","images":[],"marking_scheme":"-Toxic   - Emits harmful radiations","marks":"1","difficulty":"1"}];